// W1/W4와 동일한 HMAC + nonce dedupe 로직. 수정 시 3곳 동기화 필요.
const crypto = require('crypto');

const MAX_SKEW_MS = 5 * 60 * 1000;
const GRACE_MS = 60 * 1000;
const NONCE_TTL_MS = MAX_SKEW_MS + GRACE_MS;

const item = $input.first();
const headers = (item.json && item.json.headers) || {};
const bin = item.binary && item.binary.data;
const rawBase64 = bin && bin.data;

function fail(reason) {
  return [{ json: { verified: false, reason } }];
}

if (!rawBase64) return fail('raw_body_missing');
let raw;
try {
  raw = Buffer.from(rawBase64, 'base64').toString('utf8');
} catch (e) {
  return fail('raw_body_decode_failed');
}

let body;
try {
  body = JSON.parse(raw);
} catch (e) {
  return fail('body_not_json');
}

const ts = String(headers['x-dairect-timestamp'] || '');
const nonce = String(headers['x-dairect-nonce'] || '');
const sigHeader = String(headers['x-dairect-signature'] || '');
const secret = $env.DAIRECT_WEBHOOK_SECRET || '';

if (!secret) return fail('secret_not_configured');
if (!/^[0-9]+$/.test(ts)) return fail('timestamp_missing_or_invalid');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(nonce)) return fail('nonce_format');

const tsNum = Number(ts);
if (!Number.isFinite(tsNum)) return fail('timestamp_not_finite');
const now = Date.now();
if (Math.abs(now - tsNum) > MAX_SKEW_MS) return fail('timestamp_out_of_window');

if (!sigHeader.startsWith('sha256=')) return fail('signature_format');
const providedHex = sigHeader.slice('sha256='.length);
if (!/^[0-9a-f]{64}$/i.test(providedHex)) return fail('signature_hex_invalid');

const expected = crypto.createHmac('sha256', secret).update(`${ts}.${nonce}.${raw}`).digest('hex');
let ok = false;
try {
  const a = Buffer.from(providedHex, 'hex');
  const b = Buffer.from(expected, 'hex');
  ok = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  ok = false;
}
if (!ok) return fail('signature_mismatch');

const staticData = $getWorkflowStaticData('global');
if (!staticData.seen || typeof staticData.seen !== 'object') staticData.seen = {};
for (const k of Object.keys(staticData.seen)) {
  if (now - staticData.seen[k] > NONCE_TTL_MS) delete staticData.seen[k];
}
if (staticData.seen[nonce]) return fail('replay_detected');
staticData.seen[nonce] = now;

return [{ json: { verified: true, body } }];

// W5 Compose Email — 고객 피드백 PM 알림.
// PII: pmEmail(SMTP To 헤더), projectName(HTML), messagePreview(HTML 140자).
// 방어: stripCtrl(To/Subject 헤더 injection) + escHtml(본문 XSS) + encodeURIComponent(URL path).
function escHtml(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, (ch) => (
    { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[ch]
  ));
}
function stripCtrl(s) {
  return String(s == null ? '' : s).replace(/[\u0000-\u001F\u007F]/g, ' ');
}

const d = ($json && $json.body && $json.body.data) || {};
const to = stripCtrl(d.pmEmail || '');
const projectName = stripCtrl(d.projectName || '프로젝트');
const projectId = stripCtrl(d.projectId || '');
const preview = String(d.messagePreview || '').slice(0, 140);

const subject = stripCtrl(`[${projectName}] 고객 피드백이 도착했어요`);
const baseRaw = $env.DAIRECT_DASHBOARD_BASE_URL || 'https://dairect.kr';
const baseUrl = baseRaw.endsWith('/') ? baseRaw.slice(0, -1) : baseRaw;
const dashboardUrl = `${baseUrl}/dashboard/projects/${encodeURIComponent(projectId)}?tab=feedback`;
const html = `<!doctype html><html><body style="font-family:-apple-system,Pretendard,sans-serif;line-height:1.6;color:#111827;max-width:560px;margin:0 auto;padding:24px;">` +
  `<h1 style="font-size:20px;margin:0 0 16px;">${escHtml(projectName)} 프로젝트에 새 피드백이 도착했습니다</h1>` +
  `<pre style="background:#F9F9F7;padding:12px;border-radius:8px;white-space:pre-wrap;font-family:-apple-system,Pretendard,sans-serif;font-size:14px;color:#111827;margin:16px 0;">${escHtml(preview)}</pre>` +
  `<p style="color:#4B5563;">전체 내용과 읽음 처리는 대시보드에서 확인해주세요.</p>` +
  `<p style="margin:24px 0;"><a href="${escHtml(dashboardUrl)}" style="display:inline-block;background:#4F46E5;color:#ffffff;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:500;">대시보드로 이동 →</a></p>` +
  `<p style="margin-top:32px;color:#6B7280;font-size:13px;">— Dairect</p>` +
  `</body></html>`;

return [{ json: { to, subject, html } }];
